const data = $input.first().json;
const apiKey = "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";

// Verify message is not empty before calling API
if (!data.userMessage || data.userMessage.length < 100) {
  throw new Error('userMessage is empty or too short: ' + (data.userMessage || 'EMPTY'));
}

const bodyObj = {
  model: 'nvidia/llama-3.3-nemotron-super-49b-v1.5',
  messages: [
    { role: 'system', content: data.systemMessage },
    { role: 'user', content: data.userMessage }
  ],
  temperature: 0.6,
  top_p: 0.95,
  max_tokens: 4096
};

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://integrate.api.nvidia.com/v1/chat/completions',
  headers: {
    'Authorization': 'Bearer ' + apiKey,
    'Content-Type': 'application/json',
    'Accept': 'application/json'
  },
  body: JSON.stringify(bodyObj),
  returnFullResponse: false,
  ignoreHttpStatusErrors: false
});

const parsed = typeof response === 'string' ? JSON.parse(response) : response;
const choice = parsed.choices[0];

let rawContent = choice.message.content
  || choice.message.reasoning_content
  || choice.message.reasoning
  || '';

if (!rawContent || rawContent.length < 10) {
  throw new Error('Empty response from model. Full API response: ' + JSON.stringify(parsed).substring(0, 500));
}

const cleaned = rawContent
  .replace(/```json\n?/gi, '')
  .replace(/```\n?/gi, '')
  .trim();

const jsonStart = cleaned.indexOf('{');
const jsonEnd = cleaned.lastIndexOf('}');

if (jsonStart === -1 || jsonEnd === -1) {
  throw new Error('No JSON found in response: ' + cleaned.substring(0, 300));
}

let resumeData;
try {
  resumeData = JSON.parse(cleaned.substring(jsonStart, jsonEnd + 1));
} catch(e) {
  throw new Error('JSON parse failed: ' + cleaned.substring(jsonStart, jsonStart + 300));
}

return [{
  json: {
    user_id: data.user_id,
    profile: data.profile,
    match_score: data.match_score,
    matched_keywords: data.matched_keywords,
    missing_keywords: data.missing_keywords,
    resume_data: resumeData,
    iteration: data.iteration || 0,
    ats_score: 0
  }
}];

