const data = $input.first().json;
const apiKey = "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";

// Step 1 — Extract keywords from JD using NVIDIA
const extractBody = {
  model: 'nvidia/llama-3.3-nemotron-super-49b-v1.5',
  messages: [
    {
      role: 'system',
      content: 'You are a job description analyst. Return valid JSON only. No markdown. No explanation.'
    },
    {
      role: 'user',
      content: 'Extract key information from this job description: ' + data.jd_text + '. Return ONLY this JSON structure: {"role_title":"string","required_skills":["skill1","skill2"],"tech_stack":["tech1","tech2"],"keywords_for_ats":["keyword1","keyword2"],"experience_level":"junior/mid/senior"}'
    }
  ],
  temperature: 0.3,
  max_tokens: 1024
};

let jdData = { role_title: '', required_skills: [], tech_stack: [], keywords_for_ats: [], experience_level: 'mid' };

try {
  const extractResponse = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://integrate.api.nvidia.com/v1/chat/completions',
    headers: {
      'Authorization': 'Bearer ' + apiKey,
      'Content-Type': 'application/json',
      'Accept': 'application/json'
    },
    body: JSON.stringify(extractBody),
    returnFullResponse: false,
    ignoreHttpStatusErrors: false
  });

  const extractParsed = typeof extractResponse === 'string' ? JSON.parse(extractResponse) : extractResponse;
  const extractChoice = extractParsed.choices[0];
  let extractRaw = extractChoice.message.content || extractChoice.message.reasoning_content || extractChoice.message.reasoning || '';

  extractRaw = extractRaw.replace(/```json\n?/gi, '').replace(/```\n?/gi, '').trim();
  const s = extractRaw.indexOf('{');
  const e = extractRaw.lastIndexOf('}');
  if (s !== -1 && e !== -1) {
    jdData = JSON.parse(extractRaw.substring(s, e + 1));
  }
} catch(err) {
  // If extraction fails continue with empty jdData
}

// Step 2 — Calculate gap analysis
const userSkills = (data.profile.skills || []).map(s => s.toLowerCase());
const jdKeywords = (jdData.keywords_for_ats || []).map(k => k.toLowerCase());

const matchedKeywords = jdKeywords.filter(k => userSkills.some(s => s.includes(k) || k.includes(s)));
const missingKeywords = jdKeywords.filter(k => !userSkills.some(s => s.includes(k) || k.includes(s)));
const matchScore = jdKeywords.length > 0 ? Math.round((matchedKeywords.length / jdKeywords.length) * 100) : 50;

// Step 3 — Build the resume prompt directly here
const roleTitle = jdData.role_title || 'DevOps Engineer';
const keywords = (jdData.keywords_for_ats || []).join(', ') || 'Docker, Kubernetes, AWS, Terraform, CI/CD';
const techStack = (jdData.tech_stack || []).join(', ') || 'AWS, Docker, Kubernetes';
const profileStr = JSON.stringify(data.profile);

const userMessage = 'Create a professional ATS-optimized resume tailored for this job role: ' + roleTitle + '. You MUST include these keywords naturally throughout: ' + keywords + '. Tech stack required: ' + techStack + '. Candidate profile data: ' + profileStr + '. Instructions: Use strong action verbs, quantify all achievements with numbers, ensure 90+ ATS score. Return ONLY valid JSON with exactly this structure: {"full_name":"string","summary":"2-3 sentence summary mentioning ' + roleTitle + '","experience":[{"company":"string","role":"string","dates":"string","bullets":["quantified achievement 1","quantified achievement 2","quantified achievement 3"]}],"education":[{"degree":"string","field":"string","institution":"string","year":"string","grade":"string"}],"skills":["skill1","skill2"],"projects":[{"name":"string","description":"string","tech":"string","github":"string"}]}';

const systemMessage = 'You are an expert resume writer specializing in cloud engineering and DevOps roles. You create highly optimized ATS-friendly resumes. Always respond with valid JSON only. No markdown. No explanation. No code blocks. No conversational text.';

return [{
  json: {
    user_id: data.user_id,
    profile: data.profile,
    jd_text: data.jd_text,
    jd_data: jdData,
    match_score: matchScore,
    matched_keywords: matchedKeywords,
    missing_keywords: missingKeywords,
    systemMessage: systemMessage,
    userMessage: userMessage,
    iteration: 0
  }
}];

const data = $input.first().json;
const r = data.resume_data;
const profile = data.profile || {};

// Helper to escape LaTeX special characters
function esc(str) {
  if (!str) return '';
  return String(str)
    .replace(/\\/g, '\\textbackslash{}')
    .replace(/&/g, '\\&')
    .replace(/%/g, '\\%')
    .replace(/\$/g, '\\$')
    .replace(/#/g, '\\#')
    .replace(/_/g, '\\_')
    .replace(/\{/g, '\\{')
    .replace(/\}/g, '\\}')
    .replace(/~/g, '\\textasciitilde{}')
    .replace(/\^/g, '\\textasciicircum{}');
}

// Categorise skills
const allSkills = r.skills || [];
const cloudSkills = allSkills.filter(s => ['aws','ec2','s3','iam','gcp','azure','terraform','cloud'].some(k => s.toLowerCase().includes(k)));
const containerSkills = allSkills.filter(s => ['docker','kubernetes','k8s','helm','argocd','container'].some(k => s.toLowerCase().includes(k)));
const cicdSkills = allSkills.filter(s => ['ci','cd','jenkins','github actions','gitlab','bash','shell','linux','git'].some(k => s.toLowerCase().includes(k)));
const monitorSkills = allSkills.filter(s => ['prometheus','grafana','monitor','elk','datadog','observ'].some(k => s.toLowerCase().includes(k)));
const otherSkills = allSkills.filter(s => ![...cloudSkills,...containerSkills,...cicdSkills,...monitorSkills].includes(s));

// Build experience section
const experienceLatex = (r.experience || []).map(exp => `
\\resumeheading{${esc(exp.company)}}{${esc(profile.location || '')}}{${esc(exp.role)}}{${esc(exp.dates)}}
\\begin{resumeitem}
${(exp.bullets || []).map(b => `  \\item ${esc(b)}`).join('\n')}
\\end{resumeitem}
\\vspace{2pt}
`).join('\n');

// Build education section
const educationLatex = (r.education || []).map(edu => `
\\resumeheading{${esc(edu.institution)}}{${esc(profile.location || '')}}{${esc(edu.degree)} in ${esc(edu.field)}}{${esc(edu.year)}}
\\begin{flushleft}
\\vspace{-6pt}
${edu.grade ? `CGPA: ${esc(edu.grade)} \\\\` : ''}
\\end{flushleft}
`).join('\n');

// Build projects section
const projectsLatex = (r.projects || []).map(p => {
  const bullets = (p.description || '').split('.').filter(s => s.trim().length > 10).map(s => `  \\item ${esc(s.trim())}.`).join('\n');
  return `
\\noindent\\textbf{${esc(p.name)}} \\hfill ${p.github ? `\\href{${esc(p.github)}}{\\textbf{[GitHub]}}` : ''}\\\\
\\noindent\\textit{Tech Stack: ${esc(p.tech)}} \\hfill \\\\
\\vspace{-4pt}
\\begin{resumeitem}
${bullets}
\\end{resumeitem}
\\vspace{4pt}
`;
}).join('\n');

// Build full LaTeX document
const latex = `\\documentclass[9pt,letterpaper]{article}
\\usepackage[utf8]{inputenc}
\\usepackage[margin=0.4in]{geometry}
\\usepackage{titlesec}
\\usepackage{enumitem}
\\usepackage{hyperref}
\\usepackage{nopageno}
\\usepackage{xcolor}
\\usepackage{fontawesome5}

\\definecolor{linkblue}{RGB}{20, 70, 160}
\\hypersetup{colorlinks=true,linkcolor=linkblue,urlcolor=linkblue}

\\pagestyle{empty}

\\titleformat{\\section}{\\large\\bfseries\\scshape}{}{0em}{}[\\titlerule]
\\titlespacing{\\section}{0pt}{6pt}{3pt}

\\newlist{resumeitem}{itemize}{1}
\\setlist[resumeitem]{label=$\\bullet$, leftmargin=12pt, topsep=1pt, itemsep=1pt, parsep=0pt}

\\newcommand{\\resumeheading}[4]{
    \\noindent\\textbf{#1} \\hfill #2\\\\
    \\noindent\\textit{#3} \\hfill \\textit{#4}\\vspace{1pt}
}

\\begin{document}

\\begin{center}
    {\\Huge \\textbf{\\textsc{${esc(r.full_name || profile.full_name || 'Name')}}}}\\\\
    \\vspace{3pt}
    ${esc(profile.location || '')} \\textbullet{} ${esc(profile.phone || '')} \\textbullet{} \\href{mailto:${esc(profile.email || '')}}{${esc(profile.email || '')}} \\\\
    \\vspace{4pt}
    ${profile.linkedin ? `\\href{https://${esc(profile.linkedin)}}{\\faLinkedin{} \\textbf{LinkedIn}} \\textbullet{}` : ''}
    ${profile.github ? `\\href{https://${esc(profile.github)}}{\\faGithub{} \\textbf{GitHub}}` : ''}
\\end{center}

\\section{Education}
${educationLatex}

\\section{Technical Skills}
\\noindent \\textbf{Cloud \\& Infrastructure:} ${esc(cloudSkills.join(', '))} \\\\
\\textbf{Containerization \\& Orchestration:} ${esc(containerSkills.join(', '))} \\\\
\\textbf{CI/CD \\& Automation:} ${esc(cicdSkills.join(', '))} \\\\
\\textbf{Monitoring \\& Observability:} ${esc(monitorSkills.join(', '))} \\\\
${otherSkills.length > 0 ? `\\textbf{Other:} ${esc(otherSkills.join(', '))} \\\\` : ''}

\\section{Work Experience}
${experienceLatex}

\\section{Projects}
${projectsLatex}

\\end{document}`;

// Call YtoTech LaTeX API
const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://latex.ytotech.com/builds/sync',
  headers: {
    'Content-Type': 'application/json'
  },
  body: JSON.stringify({
    compiler: 'pdflatex',
    resources: [
      {
        main: true,
        content: latex
      }
    ]
  }),
  returnFullResponse: true,
  ignoreHttpStatusErrors: true,
  encoding: 'arraybuffer'
});

if (response.statusCode !== 200 && response.statusCode !== 201) {
  let errMsg = '';
  try {
    errMsg = Buffer.from(response.body).toString('utf8').substring(0, 500);
  } catch(e) {}
  throw new Error('LaTeX compilation failed: ' + response.statusCode + ' — ' + errMsg);
}

const filename = `resume_${data.user_id}_${Date.now()}.pdf`;

const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(response.body),
  filename,
  'application/pdf'
);

return [{
  json: {
    ...data,
    filename: filename
  },
  binary: {
    data: binaryData
  }
}];
